import{_ as r}from"./chunks/IntervalDemo.vue_vue_type_script_setup_true_lang.DZxqM-K9.js";import{C as s,o as i,c as l,ag as d,E as n,w as c,j as t,a as e}from"./chunks/framework.DLbVeA01.js";import"./chunks/Piano.QhCkvqJz.js";const q=JSON.parse('{"title":"音程的分类 Interval Classification","description":"","frontmatter":{},"headers":[],"relativePath":"intervals/classification.md","filePath":"intervals/classification.md"}'),h={name:"intervals/classification.md"},_=Object.assign(h,{setup(u){return(f,a)=>{const o=s("ClientOnly");return i(),l("div",null,[a[0]||(a[0]=d('<h1 id="音程的分类-interval-classification" tabindex="-1">音程的分类 Interval Classification <a class="header-anchor" href="#音程的分类-interval-classification" aria-label="Permalink to &quot;音程的分类 Interval Classification&quot;">​</a></h1><h2 id="按性质分类" tabindex="-1">按性质分类 <a class="header-anchor" href="#按性质分类" aria-label="Permalink to &quot;按性质分类&quot;">​</a></h2><p>音程可以按照其&quot;听感&quot;分为几大类：</p><h3 id="完全协和音程-perfect-consonances" tabindex="-1">完全协和音程 (Perfect Consonances) <a class="header-anchor" href="#完全协和音程-perfect-consonances" aria-label="Permalink to &quot;完全协和音程 (Perfect Consonances)&quot;">​</a></h3><ul><li><strong>纯一度</strong> (Unison) — 0 个半音</li><li><strong>纯八度</strong> (Octave) — 12 个半音</li><li><strong>纯五度</strong> (Perfect 5th) — 7 个半音</li><li><strong>纯四度</strong> (Perfect 4th) — 5 个半音</li></ul><p>这些音程听起来最&quot;融合&quot;，两个音几乎合为一体。</p><h3 id="不完全协和音程-imperfect-consonances" tabindex="-1">不完全协和音程 (Imperfect Consonances) <a class="header-anchor" href="#不完全协和音程-imperfect-consonances" aria-label="Permalink to &quot;不完全协和音程 (Imperfect Consonances)&quot;">​</a></h3><ul><li><strong>大三度</strong> / <strong>小三度</strong> — 4 / 3 个半音</li><li><strong>大六度</strong> / <strong>小六度</strong> — 9 / 8 个半音</li></ul><p>这些音程听起来悦耳，但两个音仍然各自可辨。和弦的&quot;明亮&quot;或&quot;忧郁&quot;感主要来自三度音程。</p><h3 id="不协和音程-dissonances" tabindex="-1">不协和音程 (Dissonances) <a class="header-anchor" href="#不协和音程-dissonances" aria-label="Permalink to &quot;不协和音程 (Dissonances)&quot;">​</a></h3><ul><li><strong>大二度</strong> / <strong>小二度</strong> — 2 / 1 个半音</li><li><strong>大七度</strong> / <strong>小七度</strong> — 11 / 10 个半音</li><li><strong>增四度/减五度</strong> (Tritone) — 6 个半音</li></ul><p>这些音程听起来有&quot;紧张感&quot;，需要&quot;解决&quot;到协和音程。</p><h2 id="按度数分类" tabindex="-1">按度数分类 <a class="header-anchor" href="#按度数分类" aria-label="Permalink to &quot;按度数分类&quot;">​</a></h2><p>在传统乐理中，音程也用&quot;度&quot;来命名：</p><table tabindex="0"><thead><tr><th>度数</th><th>包含的音名数</th><th>可能的变化形式</th></tr></thead><tbody><tr><td>一度</td><td>1</td><td>纯一度、增一度</td></tr><tr><td>二度</td><td>2</td><td>小二度、大二度、增二度</td></tr><tr><td>三度</td><td>3</td><td>减三度、小三度、大三度、增三度</td></tr><tr><td>四度</td><td>4</td><td>减四度、纯四度、增四度</td></tr><tr><td>五度</td><td>5</td><td>减五度、纯五度、增五度</td></tr><tr><td>六度</td><td>6</td><td>小六度、大六度</td></tr><tr><td>七度</td><td>7</td><td>减七度、小七度、大七度</td></tr><tr><td>八度</td><td>8</td><td>减八度、纯八度、增八度</td></tr></tbody></table>',15)),n(o,null,{default:c(()=>[n(r)]),_:1}),a[1]||(a[1]=t("h2",{id:"相关主题",tabindex:"-1"},[e("相关主题 "),t("a",{class:"header-anchor",href:"#相关主题","aria-label":'Permalink to "相关主题"'},"​")],-1)),a[2]||(a[2]=t("ul",null,[t("li",null,[t("a",{href:"/intervals/consonance.html"},"协和与不协和"),e(" — 深入理解音程的听感")]),t("li",null,[t("a",{href:"/chords/"},"和弦"),e(" — 音程如何构成和弦")])],-1))])}}});export{q as __pageData,_ as default};
